import React, { useState } from 'react';
import { loginAdmin } from '../../services/api';
import { FaUser, FaLock, FaRobot, FaArrowRight, FaShieldAlt, FaBrain, FaCheckCircle } from 'react-icons/fa';

const LoginPage = ({ onLogin }) => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    try {
      const response = await loginAdmin(username, password);
      if (response.data.access_token) {
        onLogin(response.data.access_token);
      }
    } catch (err) {
      setError('Invalid credentials! Use varshini / varshu');
    }
    setLoading(false);
  };

  return (
    <div style={{
      minHeight: '100vh',
      position: 'relative',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      padding: '16px',
      overflow: 'hidden'
    }}>
      {/* Background Image */}
      <div style={{
        position: 'absolute',
        top: 0,
        left: 0,
        right: 0,
        bottom: 0,
        backgroundImage: 'url("https://images.unsplash.com/photo-1497366216548-37526070297c?ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D&auto=format&fit=crop&w=2070&q=80")',
        backgroundSize: 'cover',
        backgroundPosition: 'center',
        backgroundRepeat: 'no-repeat'
      }}></div>

      {/* Dark Overlay for better text visibility */}
      <div style={{
        position: 'absolute',
        top: 0,
        left: 0,
        right: 0,
        bottom: 0,
        background: 'linear-gradient(135deg, rgba(0,0,0,0.85) 0%, rgba(0,50,30,0.8) 100%)'
      }}></div>

      {/* Animated Green Glow Elements */}
      <div style={{
        position: 'absolute',
        inset: 0,
        overflow: 'hidden'
      }}>
        <div style={{
          position: 'absolute',
          top: '-160px',
          right: '-160px',
          width: '320px',
          height: '320px',
          background: '#10b981',
          borderRadius: '50%',
          filter: 'blur(80px)',
          opacity: 0.2,
          animation: 'blob 7s infinite'
        }}></div>
        <div style={{
          position: 'absolute',
          bottom: '-160px',
          left: '-160px',
          width: '320px',
          height: '320px',
          background: '#059669',
          borderRadius: '50%',
          filter: 'blur(80px)',
          opacity: 0.2,
          animation: 'blob 7s infinite 2s'
        }}></div>
        <div style={{
          position: 'absolute',
          top: '50%',
          left: '50%',
          transform: 'translate(-50%, -50%)',
          width: '320px',
          height: '320px',
          background: '#34d399',
          borderRadius: '50%',
          filter: 'blur(80px)',
          opacity: 0.15,
          animation: 'blob 7s infinite 4s'
        }}></div>
      </div>

      {/* Main Container */}
      <div style={{
        position: 'relative',
        zIndex: 10,
        width: '100%',
        maxWidth: '1024px'
      }}>
        <div style={{
          display: 'grid',
          gridTemplateColumns: '1fr 1fr',
          gap: '32px'
        }}>
          {/* Left Side - Brand Section */}
          <div style={{
            display: 'flex',
            flexDirection: 'column',
            justifyContent: 'center',
            color: 'white',
            gap: '24px',
            backdropFilter: 'blur(10px)',
            background: 'rgba(0,0,0,0.3)',
            borderRadius: '24px',
            padding: '32px'
          }}>
            <div style={{
              display: 'inline-flex',
              alignItems: 'center',
              gap: '12px',
              background: 'rgba(16, 185, 129, 0.2)',
              backdropFilter: 'blur(8px)',
              borderRadius: '16px',
              padding: '16px',
              width: 'fit-content',
              border: '1px solid rgba(16, 185, 129, 0.3)'
            }}>
              <div style={{
                background: 'linear-gradient(135deg, #10b981, #059669)',
                padding: '12px',
                borderRadius: '12px'
              }}>
                <FaBrain size={32} color="white" />
              </div>
              <div style={{
                background: 'linear-gradient(135deg, #10b981, #059669)',
                padding: '12px',
                borderRadius: '12px'
              }}>
                <FaRobot size={32} color="white" />
              </div>
            </div>

            <h1 style={{
              fontSize: '48px',
              fontWeight: 'bold',
              lineHeight: 1.2,
              margin: 0
            }}>
              AI Resume
              <br />
              <span style={{
                background: 'linear-gradient(135deg, #10b981, #34d399)',
                WebkitBackgroundClip: 'text',
                WebkitTextFillColor: 'transparent',
                backgroundClip: 'text'
              }}>
                Screening System
              </span>
            </h1>

            <p style={{
              fontSize: '18px',
              color: '#d1fae5',
              lineHeight: 1.6,
              margin: 0
            }}>
              Intelligent parsing, automated screening, and smart candidate matching powered by advanced AI technology.
            </p>

            <div style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
              <div style={{ display: 'flex', alignItems: 'center', gap: '12px', color: '#d1fae5' }}>
                <FaCheckCircle color="#10b981" />
                <span>AI-powered resume parsing</span>
              </div>
              <div style={{ display: 'flex', alignItems: 'center', gap: '12px', color: '#d1fae5' }}>
                <FaCheckCircle color="#10b981" />
                <span>Smart candidate ranking</span>
              </div>
              <div style={{ display: 'flex', alignItems: 'center', gap: '12px', color: '#d1fae5' }}>
                <FaCheckCircle color="#10b981" />
                <span>Real-time analytics dashboard</span>
              </div>
            </div>

            {/* Stats */}
            <div style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(3, 1fr)',
              gap: '16px',
              paddingTop: '24px'
            }}>
              <div style={{
                background: 'rgba(16, 185, 129, 0.15)',
                backdropFilter: 'blur(8px)',
                borderRadius: '12px',
                padding: '12px',
                textAlign: 'center',
                border: '1px solid rgba(16, 185, 129, 0.3)'
              }}>
                <div style={{ fontSize: '24px', fontWeight: 'bold', color: '#34d399' }}>500+</div>
                <div style={{ fontSize: '12px', color: '#d1fae5' }}>Resumes Processed</div>
              </div>
              <div style={{
                background: 'rgba(16, 185, 129, 0.15)',
                backdropFilter: 'blur(8px)',
                borderRadius: '12px',
                padding: '12px',
                textAlign: 'center',
                border: '1px solid rgba(16, 185, 129, 0.3)'
              }}>
                <div style={{ fontSize: '24px', fontWeight: 'bold', color: '#34d399' }}>98%</div>
                <div style={{ fontSize: '12px', color: '#d1fae5' }}>Accuracy Rate</div>
              </div>
              <div style={{
                background: 'rgba(16, 185, 129, 0.15)',
                backdropFilter: 'blur(8px)',
                borderRadius: '12px',
                padding: '12px',
                textAlign: 'center',
                border: '1px solid rgba(16, 185, 129, 0.3)'
              }}>
                <div style={{ fontSize: '24px', fontWeight: 'bold', color: '#34d399' }}>24/7</div>
                <div style={{ fontSize: '12px', color: '#d1fae5' }}>AI Processing</div>
              </div>
            </div>
          </div>

          {/* Right Side - Login Form */}
          <div>
            <div style={{
              background: 'rgba(0, 0, 0, 0.6)',
              backdropFilter: 'blur(16px)',
              borderRadius: '24px',
              boxShadow: '0 25px 50px -12px rgba(0,0,0,0.5)',
              padding: '32px',
              border: '1px solid rgba(16, 185, 129, 0.3)'
            }}>
              {/* Mobile Brand */}
              <div style={{
                display: 'none',
                textAlign: 'center',
                marginBottom: '24px'
              }}>
                <div style={{
                  display: 'inline-flex',
                  alignItems: 'center',
                  gap: '8px',
                  background: 'linear-gradient(135deg, #10b981, #059669)',
                  padding: '8px',
                  borderRadius: '12px',
                  marginBottom: '12px'
                }}>
                  <FaBrain size={24} color="white" />
                  <FaRobot size={24} color="white" />
                </div>
                <h2 style={{ fontSize: '24px', fontWeight: 'bold', color: 'white', margin: 0 }}>AI Resume Screening</h2>
                <p style={{ color: '#d1fae5', fontSize: '14px', margin: '8px 0 0 0' }}>Admin Portal</p>
              </div>

              <div style={{
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'space-between',
                marginBottom: '24px'
              }}>
                <h3 style={{ fontSize: '28px', fontWeight: 'bold', color: 'white', margin: 0 }}>Admin Login</h3>
                <FaShieldAlt size={24} color="#10b981" />
              </div>

              {/* Error Alert */}
              {error && (
                <div style={{
                  marginBottom: '16px',
                  background: 'rgba(220, 38, 38, 0.2)',
                  border: '1px solid rgba(220, 38, 38, 0.5)',
                  borderRadius: '12px',
                  padding: '12px'
                }}>
                  <p style={{ color: '#fecaca', fontSize: '14px', textAlign: 'center', margin: 0 }}>{error}</p>
                </div>
              )}

              <form onSubmit={handleSubmit} style={{ display: 'flex', flexDirection: 'column', gap: '20px' }}>
                {/* Username Field */}
                <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
                  <label style={{ fontSize: '14px', fontWeight: '500', color: '#d1fae5' }}>
                    Username
                  </label>
                  <div style={{ position: 'relative' }}>
                    <div style={{
                      position: 'absolute',
                      left: '12px',
                      top: '50%',
                      transform: 'translateY(-50%)',
                      pointerEvents: 'none'
                    }}>
                      <FaUser color="#10b981" size={18} />
                    </div>
                    <input
                      type="text"
                      placeholder="Enter your username"
                      value={username}
                      onChange={(e) => setUsername(e.target.value)}
                      style={{
                        width: '100%',
                        padding: '14px 14px 14px 42px',
                        background: 'rgba(255,255,255,0.1)',
                        border: '1px solid rgba(16, 185, 129, 0.3)',
                        borderRadius: '12px',
                        color: 'white',
                        fontSize: '16px',
                        outline: 'none',
                        transition: 'all 0.3s'
                      }}
                      required
                      disabled={loading}
                      onFocus={(e) => e.target.style.borderColor = '#10b981'}
                      onBlur={(e) => e.target.style.borderColor = 'rgba(16, 185, 129, 0.3)'}
                    />
                  </div>
                </div>

                {/* Password Field */}
                <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
                  <label style={{ fontSize: '14px', fontWeight: '500', color: '#d1fae5' }}>
                    Password
                  </label>
                  <div style={{ position: 'relative' }}>
                    <div style={{
                      position: 'absolute',
                      left: '12px',
                      top: '50%',
                      transform: 'translateY(-50%)',
                      pointerEvents: 'none'
                    }}>
                      <FaLock color="#10b981" size={18} />
                    </div>
                    <input
                      type="password"
                      placeholder="Enter your password"
                      value={password}
                      onChange={(e) => setPassword(e.target.value)}
                      style={{
                        width: '100%',
                        padding: '14px 14px 14px 42px',
                        background: 'rgba(255,255,255,0.1)',
                        border: '1px solid rgba(16, 185, 129, 0.3)',
                        borderRadius: '12px',
                        color: 'white',
                        fontSize: '16px',
                        outline: 'none',
                        transition: 'all 0.3s'
                      }}
                      required
                      disabled={loading}
                      onFocus={(e) => e.target.style.borderColor = '#10b981'}
                      onBlur={(e) => e.target.style.borderColor = 'rgba(16, 185, 129, 0.3)'}
                    />
                  </div>
                </div>

                {/* Forgot Password Link */}
                <div style={{ textAlign: 'right' }}>
                  <a href="#" style={{ color: '#10b981', fontSize: '14px', textDecoration: 'none' }}>
                    Forgot password?
                  </a>
                </div>

                {/* Login Button */}
                <button
                  type="submit"
                  disabled={loading}
                  style={{
                    position: 'relative',
                    width: '100%',
                    background: 'linear-gradient(135deg, #059669, #10b981)',
                    border: 'none',
                    borderRadius: '12px',
                    padding: '2px',
                    cursor: loading ? 'not-allowed' : 'pointer',
                    transition: 'all 0.3s'
                  }}
                >
                  <div style={{
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    gap: '8px',
                    background: 'rgba(0, 0, 0, 0.7)',
                    borderRadius: '10px',
                    padding: '12px',
                    transition: 'all 0.3s'
                  }}>
                    <span style={{ color: 'white', fontWeight: '600', fontSize: '16px' }}>
                      {loading ? 'Authenticating...' : 'Login to Dashboard'}
                    </span>
                    {!loading && <FaArrowRight color="#10b981" size={14} />}
                    {loading && (
                      <div style={{
                        width: '16px',
                        height: '16px',
                        border: '2px solid #10b981',
                        borderTopColor: 'transparent',
                        borderRadius: '50%',
                        animation: 'spin 0.6s linear infinite'
                      }}></div>
                    )}
                  </div>
                </button>

                {/* Demo Credentials Hint */}
                <div style={{
                  marginTop: '16px',
                  padding: '12px',
                  background: 'rgba(16, 185, 129, 0.1)',
                  borderRadius: '12px',
                  border: '1px solid rgba(16, 185, 129, 0.3)'
                }}>
                  <p style={{ fontSize: '12px', color: '#d1fae5', textAlign: 'center', margin: 0 }}>
                    🔐 Demo Credentials: <span style={{ fontFamily: 'monospace', color: '#34d399', fontWeight: 'bold' }}>varshini</span> / <span style={{ fontFamily: 'monospace', color: '#34d399', fontWeight: 'bold' }}>varshu</span>
                  </p>
                </div>
              </form>

              {/* Footer */}
              <div style={{
                marginTop: '24px',
                paddingTop: '16px',
                borderTop: '1px solid rgba(16, 185, 129, 0.2)',
                textAlign: 'center'
              }}>
                <p style={{ fontSize: '12px', color: '#9ca3af', margin: 0 }}>
                  Secure admin access only • Protected by AI encryption
                </p>
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* Add animation keyframes */}
      <style>{`
        @keyframes blob {
          0%, 100% { transform: translate(0px, 0px) scale(1); }
          33% { transform: translate(30px, -50px) scale(1.1); }
          66% { transform: translate(-20px, 20px) scale(0.9); }
        }

        @keyframes spin {
          0% { transform: rotate(0deg); }
          100% { transform: rotate(360deg); }
        }

        @media (max-width: 768px) {
          .responsive-grid {
            grid-template-columns: 1fr !important;
          }
          .brand-section {
            display: none !important;
          }
          .mobile-brand {
            display: block !important;
          }
        }
      `}</style>
    </div>
  );
};

export default LoginPage;
